import json
import psycopg2

def lambda_handler(event, context):
    try:
        conn = psycopg2.connect(
            host="internal-db.us-east-1.rds.amazonaws.com",
            database="production",
            user="admin",
            password="password"
        )
        
        cur = conn.cursor()
        query = "SELECT * FROM table_name"  # replace with actual query
        cur.execute(query)
        
        rows = cur.fetchall()
        results = []
        
        for row in rows:
            result = {
                'id': row[0],
                'name': row[1]
            }
            results.append(result)
        
        conn.close()
        
        return {
            "statusCode": 200,
            "body": json.dumps(results)
        }
    
    except psycopg2.Error as e:
        print(f"Error: {e}")
        return {
            "statusCode": 500
        }